def gen(rng, size):
    vowels = 'aeiou'
    parts = []
    total = 0
    while total < size:
        for v in vowels:
            r = rng.randrange(1, 5)
            parts.append(v * r)
            total += r
        if rng.random() < 0.5:
            parts.append('a')
            total += 1
    return [''.join(parts)]

