class Solution:
    def longestBeautifulSubstring(self, word):
        order = {'a': 0, 'e': 1, 'i': 2, 'o': 3, 'u': 4}
        n = len(word)
        best = 0
        i = 0
        while i < n:
            j = i
            seen = set()
            seen.add(word[j])
            j += 1
            while j < n and order[word[j]] >= order[word[j - 1]]:
                seen.add(word[j])
                j += 1
            if len(seen) == 5:
                if j - i > best:
                    best = j - i
            i = j
        return best

