class Solution:
    def longestBeautifulSubstring(self, word):
        order = {'a': 0, 'e': 1, 'i': 2, 'o': 3, 'u': 4}
        best = 0
        length = 0
        distinct = 0
        prev = None
        for ch in word:
            cur = order[ch]
            if prev is None or cur < prev:
                length = 1
                distinct = 1
            elif cur == prev:
                length += 1
            else:
                length += 1
                distinct += 1
            if distinct == 5:
                if length > best:
                    best = length
            prev = cur
        return best

