var longestBeautifulSubstring = function(word) {
    const order = { a: 0, e: 1, i: 2, o: 3, u: 4 };
    let best = 0, length = 0, distinct = 0, prev = -1, started = false;
    for (const ch of word) {
        const cur = order[ch];
        if (!started || cur < prev) {
            length = 1;
            distinct = 1;
            started = true;
        } else if (cur === prev) {
            length += 1;
        } else {
            length += 1;
            distinct += 1;
        }
        if (distinct === 5 && length > best) best = length;
        prev = cur;
    }
    return best;
};
